const body = $input.first().json.body || {};
const branding = body.branding || {};
const copy = body.copy || {};
const strategy = body.strategy || {};
const images = branding.images || {};
const colors = Array.isArray(branding.colors) ? branding.colors : Object.values(branding.colors || {});
const fontsList = Array.isArray(branding.fonts)
  ? branding.fonts.map((font) => typeof font === "string" ? font : font.family).filter(Boolean)
  : [];

const palette = colors.slice(0, 6).join(", ") || "brand colors";
const fonts = fontsList.slice(0, 3).join(", ");
const brandName = copy.brand_name || branding.title || "the brand";
const tone = (copy.tone || []).join(", ") || (strategy.mood_keywords || []).slice(0, 3).join(", ") || "modern, confident";
const headline = copy.hero_headline || copy.tagline || "";
const cta = copy.primary_cta || "";
const archetype = strategy.brand_archetype || "";
const designMd = String(body.design_md || "").slice(0, 2400);

const isHttp = (value) => /^https?:\/\//.test(String(value || ""));
const isDataImage = (value) => /^data:image\/(png|jpe?g|webp);base64,/.test(String(value || ""));
const imageUrls = [
  isHttp(images.logo) ? images.logo : null,
  isDataImage(body.screenshot) ? body.screenshot : null,
  isHttp(images.ogImage) ? images.ogImage : null,
].filter(Boolean);

const referenceRules = [
  "Reference priority is strict: first the logo/brand mark, second the homepage screenshot, third the OG image only as secondary inspiration.",
  "The generated asset must visibly belong to the same brand system as the logo: match the mark geometry, color relationships, contrast, spacing, and polish.",
  "Do not invent a different logo, mascot, app icon, or unrelated symbol.",
  "Use the homepage screenshot for layout density, surface treatment, typography feel, and real product context.",
].join(" ");

const baseStyle = [
  `Brand: ${brandName}.`,
  `Tone: ${tone}.`,
  archetype ? `Archetype: ${archetype}.` : "",
  `Palette: ${palette}.`,
  fonts ? `Typography: ${fonts}.` : "",
  headline ? `Headline: ${headline}.` : "",
  cta ? `CTA: ${cta}.` : "",
  referenceRules,
  `Design system context: ${designMd}`,
].filter(Boolean).join(" ");

if (body.asset_prompt) {
  return [{
    json: {
      type: body.asset_type || "custom",
      image_size: body.image_size || "landscape_16_9",
      image_urls: imageUrls,
      prompt: `${body.asset_prompt}\n\nBrand context:\n${baseStyle}`,
    },
  }];
}

const specs = [
  ["hero", "landscape_16_9", `Hero marketing image for ${brandName}. ${baseStyle} Concept: ${headline || "the brand promise"}. High-end website hero visual.`],
  ["ig_post", "square_hd", `Instagram post for ${brandName}. ${baseStyle} Square composition with one strong subject and short readable text treatment: ${brandName}. Premium.`],
  ["og_card", "landscape_16_9", `Open graph card for ${brandName}. ${baseStyle} Editorial preview image with clear hierarchy and product-led visual language.`],
  ["ig_story", "portrait_16_9", `Instagram story for ${brandName}. ${baseStyle} Tall mobile composition with a strong central visual and concise headline area.`],
];

return specs.map(([type, image_size, prompt]) => ({ json: { type, image_size, image_urls: imageUrls, prompt } }));
